mapper.select:
SELECT RNUM , knoId , knoNm , orgnztId , orgnztNm , knoTypeNm , userNm , appYmd , frstRegisterId , frstRegistPnttm , lastUpdusrId , lastUpdtPnttm
FROM ( SELECT Row_Number() OVER(ORDER BY A.FRST_REGIST_PNTTM desc ) as RNUM , A.KNWLDG_ID knoId , A.KNWLDG_NM knoNm , C.ORGNZT_ID orgnztId , C.ORGNZT_NM orgnztNm , B.KNWLDG_TY_NM knoTypeNm , D.USER_NM userNm , FORMAT(CONVERT(datetime, A.EVL_DE), 'yyyy-MM-dd') appYmd , A.FRST_REGISTER_ID frstRegisterId , A.FRST_REGIST_PNTTM frstRegistPnttm , A.LAST_UPDUSR_ID lastUpdusrId , A.LAST_UPDT_PNTTM lastUpdtPnttm FROM XBOLTDLM.COMTNDAMKNOIFM A, XBOLTDLM.COMTNDAMMAPKNO B, XBOLTDLM.COMTNDAMMAPTEAM C, XBOLTDLM.COMVNUSERMASTER D WHERE C.ORGNZT_ID = B.ORGNZT_ID AND A.KNWLDG_TY_CODE = B.KNWLDG_TY_CODE AND A.FRST_REGISTER_ID = D.ESNTL_ID AND A.OTHBC_AT = 'Y' AND A.KNWLDG_EVL = '1'
AND C.ORGNZT_ID = #{orgnztId}
AND A.KNWLDG_NM like N'%'+#{searchValue}+'%'
AND D.USER_NM like N'%'+#{searchValue}+'%'
) brd

SELECT FRST_REGISTER_Id
FROM XBOLTDLM.COMTNDAMKNOIFM
WHERE KNWLDG_ID = #{knwldgId}

SELECT TOP 1 'DMID_' + CAST(CAST(SUBSTRING(KNWLDG_ID, 6, LEN(KNWLDG_ID) - 5) AS BIGINT) + 1 AS VARCHAR)
FROM XBOLTDLM.COMTNDAMKNOIFM
ORDER BY KNWLDG_ID DESC;

SELECT KNWLDG_TY_CODE
FROM XBOLTDLM.COMTNDAMMAPKNO
WHERE ORGNZT_ID = #{project}

mapper.insert:
 
    INSERT 
      INTO  XBOLTDLM.COMTNDAMKNOIFM
         (  KNWLDG_ID
         ,  KNWLDG_NM
         ,	ORGNZT_ID
         ,  KNWLDG_TY_CODE
         ,  KNWLDG_CN
         ,  COLCT_DE
         ,  OTHBC_AT
         ,  ATCH_FILE_ID
	     ,	FRST_REGISTER_ID
	     ,	FRST_REGIST_PNTTM
         ,  LAST_UPDUSR_ID			     	         
         ,  LAST_UPDT_PNTTM
         ,  CORP_ID
		 ,  SVC_CI_ID
		 ,  SYMPTON_DESC
		 ,  ROOTCAUSE_DESC
		 ,  KNWLDG_EVL 
         ) 
    VALUES  
         (  #{knwldgId}
         ,  #{knwldgNm}
         ,  #{project}		         		         
         ,  #{knoTypeCd}
         ,  #{knwldgCn}
         ,  GETDATE()
         ,  'Y'
         ,  #{AtchFileId}
         ,  #{userId}
         ,  GETDATE()      		 
         ,  #{userId}
         ,  GETDATE()
         ,  #{srArea1}
         ,  #{srArea2}
         ,  #{sympton}
         ,  #{rootCause}
         , '1'
         )
